constType:
∀ {𝕜 : Type u_1} {inst : NontriviallyNormedField 𝕜} {E : Type u_2} {inst_1 : SeminormedAddCommGroup E}
  {inst_2 : NormedSpace 𝕜 E} {inst_3 : IsUltrametricDist E} {F : Type u_3} {inst_4 : SeminormedAddCommGroup F}
  {inst_5 : NormedSpace 𝕜 F} {inst_6 : IsUltrametricDist F} (ι : E →ₗᵢ[𝕜] F)
  [self : SphericallyCompleteSpace.IsSphericalCompletion ι], SphericallyCompleteSpace F

∀ {𝕜 : Type u_1} {inst : NontriviallyNormedField 𝕜} {E : Type u_2} {inst_1 : NormedAddCommGroup E}
  {inst_2 : NormedSpace 𝕜 E} {D : Submodule 𝕜 E} {F : Type u_3} {inst_3 : NormedAddCommGroup F}
  {inst_4 : NormedSpace 𝕜 F} {inst_5 : IsUltrametricDist E} {inst_6 : IsUltrametricDist F}
  [self : SphericallyCompleteSpace.IsHahnBanachPair D F] (f : ↥D →L[𝕜] F),
  ∃ f', (∀ (v : E) (hv : v ∈ D), f' v = f ⟨v, hv⟩) ∧ ‖f'‖ = ‖f‖

∀ {𝕜 : Type u_1} {inst : NontriviallyNormedField 𝕜} {E : Type u_2} {inst_1 : SeminormedAddCommGroup E}
  {inst_2 : NormedSpace 𝕜 E} {inst_3 : IsUltrametricDist E} {F : Type u_3} {inst_4 : SeminormedAddCommGroup F}
  {inst_5 : NormedSpace 𝕜 F} {inst_6 : IsUltrametricDist F} {ι : E →ₗᵢ[𝕜] F}
  [self : SphericallyCompleteSpace.IsSphericalCompletion ι] (D : Submodule 𝕜 F),
  SphericallyCompleteSpace ↥D → ι.range ≤ D → D = ⊤
